noncompliant:
// Noncompliant: Missing co_return on some paths
cppcoro::task<int> getValue(bool condition) {
    if (condition) {
        co_return 42;
    }
    // Missing co_return - undefined behavior
}

cppcoro::task<std::string> processData(int type) {
    switch (type) {
        case 1:
            co_return "type1";
        case 2:
            co_return "type2";
        default:
            break; // Missing co_return
    }
    // Falls off end without co_return
}

compliant:
// Compliant: co_return on all execution paths
cppcoro::task<int> getValue(bool condition) {
    if (condition) {
        co_return 42;
    }
    co_return 0; // Explicit return for all paths
}

// Compliant: Promise type provides return_void()
struct VoidPromise {
    auto return_void() { /* implementation */ }
    // ... other promise methods
};

cppcoro::task<void> processWithVoidReturn() {
    co_await doWork();
    // return_void() called automatically
}
